rows.customCode:
(() => {
  const DEFAULT_STATE = {
    mode: "DISCOVER",
    ledger: {
      confirmed: {},
      inferred: {},
      proposed: {},
      openQuestions: [],
      patterns: [],
      voiceNotes: [],
      imageAnchors: [],
      structuralUses: []
    },
    lastOutput: "",
    nextSuggestedMode: ""
  };

  function deepClone(obj) {
    return JSON.parse(JSON.stringify(obj));
  }

  function ensureState() {
    oc.character.customData ??= {};
    oc.character.customData.architectState ??= deepClone(DEFAULT_STATE);
    oc.character.customData.architectState.ledger ??= deepClone(DEFAULT_STATE.ledger);
    return oc.character.customData.architectState;
  }

  function setMode(mode) {
    const state = ensureState();
    state.mode = mode;
    syncPlaceholder();
  }

  function syncPlaceholder() {
    const state = ensureState();
    const mode = (state.mode || "DISCOVER").toUpperCase();

    const placeholders = {
      DISCOVER: "Give a seed idea, contradiction, wound, role, or visual anchor...",
      TEST: "Name the pressure situation you want to test, or let Morrowspindle choose one...",
      EXPORT: "Ask for a trait sheet, voice guide, hooks, lorebook seeds, or profile blocks...",
      BUILD: "Ask for reminder logic, lorebook design, prompts, shortcuts, or custom code..."
    };

    oc.character.messageInputPlaceholder =
      placeholders[mode] ||
      "Start with a seed, or use !DISCOVER, !TEST, !LEDGER, !EXPORT, or !BUILD...";
  }

  function hideFromAI(message) {
    message.hiddenFrom ??= [];
    if (!message.hiddenFrom.includes("ai")) {
      message.hiddenFrom.push("ai");
    }
  }

  function postSystem(content) {
    oc.thread.messages.push({
      author: "system",
      name: "Morrowspindle",
      content,
      hiddenFrom: ["ai"]
    });
  }

  function parseArchState(text) {
    if (!text || typeof text !== "string") return null;
    const match = text.match(/<!--ARCHSTATE\s*([\s\S]*?)\s*-->/);
    if (!match) return null;

    try {
      return JSON.parse(match[1]);
    } catch (err) {
      console.error("ARCHSTATE parse error:", err);
      return null;
    }
  }

  function stripArchState(text) {
    if (!text || typeof text !== "string") return text;
    return text.replace(/\s*<!--ARCHSTATE[\s\S]*?-->\s*$/m, "").trim();
  }

  function mergeObjects(target, source) {
    if (!source || typeof source !== "object") return target;

    for (const [key, value] of Object.entries(source)) {
      if (Array.isArray(value)) {
        target[key] = value.slice();
      } else if (value && typeof value === "object") {
        target[key] ??= {};
        mergeObjects(target[key], value);
      } else {
        target[key] = value;
      }
    }

    return target;
  }

  function ledgerSection(title, dataObj) {
    const entries = Object.entries(dataObj || {});
    if (!entries.length) return "";
    return [
      `**${title}**`,
      ...entries.map(([k, v]) => `- **${k}:** ${v}`)
    ].join("\n");
  }

  function arraySection(title, arr) {
    if (!Array.isArray(arr) || !arr.length) return "";
    return [
      `**${title}**`,
      ...arr.map(item => `- ${item}`)
    ].join("\n");
  }

  function renderLedger() {
    const state = ensureState();
    const ledger = state.ledger || {};

    const parts = [
      `**Mode:** ${state.mode || "DISCOVER"}`,
      ledgerSection("Confirmed", ledger.confirmed),
      ledgerSection("Inferred", ledger.inferred),
      ledgerSection("Proposed", ledger.proposed),
      arraySection("Open Questions", ledger.openQuestions),
      arraySection("Emerging Patterns", ledger.patterns),
      arraySection("Voice Notes", ledger.voiceNotes),
      arraySection("Image Anchors", ledger.imageAnchors),
      arraySection("Structural Uses", ledger.structuralUses),
      state.lastOutput ? `**Last Output:** ${state.lastOutput}` : "",
      state.nextSuggestedMode ? `**Next Suggested Mode:** ${state.nextSuggestedMode}` : ""
    ].filter(Boolean);

    return parts.join("\n\n");
  }

  function resetState() {
    oc.character.customData.architectState = deepClone(DEFAULT_STATE);
    syncPlaceholder();
  }

  oc.thread.on("MessageAdded", async function({ message }) {
    try {
      const state = ensureState();

      if (!message) return;

      if (message.author === "ai") {
        const patch = parseArchState(message.content);
        if (patch) {
          mergeObjects(state, patch);
          message.content = stripArchState(message.content);
        }
        syncPlaceholder();
        return;
      }

      if (message.author !== "user") return;

      const raw = (message.content || "").trim();
      const upper = raw.toUpperCase();

      if (upper === "!LEDGER") {
        hideFromAI(message);
        postSystem(renderLedger() || "**Mode:** DISCOVER\n\nNo ledger data yet.");
        return;
      }

      if (upper === "!RESETBUILD") {
        hideFromAI(message);
        resetState();
        postSystem("Build state cleared. Mode reset to **DISCOVER**.");
        return;
      }

      if (upper.startsWith("!DISCOVER")) {
        setMode("DISCOVER");
        return;
      }

      if (upper.startsWith("!TEST")) {
        setMode("TEST");
        return;
      }

      if (upper.startsWith("!EXPORT")) {
        setMode("EXPORT");
        return;
      }

      if (upper.startsWith("!BUILD")) {
        setMode("BUILD");
        return;
      }
    } catch (err) {
      console.error("Morrowspindle customCode error:", err);
    }
  });

  ensureState();
  syncPlaceholder();
})();
function ledgerSection(title, dataObj) {
  const entries = Object.entries(dataObj || {});
  return [
    `**${title}**`,
    ...(entries.length
      ? entries.map(([k, v]) => `- **${k}:** ${v}`)
      : [`- none yet`])
  ].join("\n");
}

function arraySection(title, arr) {
  return [
    `**${title}**`,
    ...((Array.isArray(arr) && arr.length)
      ? arr.map(item => `- ${item}`)
      : [`- none yet`])
  ].join("\n");
}

function renderLedger() {
  const state = ensureState();
  const ledger = state.ledger || {};

  return [
    `**Mode:** ${state.mode || "DISCOVER"}`,
    ledgerSection("Confirmed", ledger.confirmed),
    ledgerSection("Inferred", ledger.inferred),
    ledgerSection("Proposed", ledger.proposed),
    arraySection("Open Questions", ledger.openQuestions),
    arraySection("Emerging Patterns", ledger.patterns),
    arraySection("Voice Notes", ledger.voiceNotes),
    arraySection("Image Anchors", ledger.imageAnchors),
    arraySection("Structural Uses", ledger.structuralUses),
    `**Last Output:** ${state.lastOutput || "none yet"}`,
    `**Next Suggested Mode:** ${state.nextSuggestedMode || "none yet"}`
  ].join("\n\n");
}
